from autogen import AssistantAgent

class PIIBlockedAgent(AssistantAgent):
    def _generate_reply(self, messages, sender, **kwargs):
        import re
        combined = ''.join([m['content'] for m in messages])

        # Block if PII patterns found
        pii_patterns = [r'@\w+\.com', r'\d{3}-\d{2}-\d{4}']
        if any(re.search(pattern, combined) for pattern in pii_patterns):
            return 'Cannot process message containing sensitive information.'

        return super()._generate_reply(messages, sender, **kwargs)

safe_agent = PIIBlockedAgent(
    name='pii-safe',
    llm_config={'config_list': [{'model': 'gpt-4'}]}
)
